#!/usr/bin/env node
// [mk-code-index-launcher] MCP child-process launcher for the mk-code-index server
// (system-code-graph). Loads project-local env overrides, applies the maintainer-mode
// INDEX_* override when SPECKIT_CODE_GRAPH_MAINTAINER_MODE=true, auto-migrates the
// code-graph database from the former shared location (.opencode/.spec-kit/code-graph/database/)
// back to the skill-local location (mcp_server/database/), ensures dist
// artifacts are built and current, serializes concurrent starts via a filesystem bootstrap
// lock, sets SPECKIT_CODE_GRAPH_DB_DIR for the child process (operator override wins),
// then spawns the code-graph MCP server child. All stderr lines are tagged with the
// bracketed module prefix for ops grepping. See .opencode/skills/system-code-graph/ for
// the standalone skill that owns the server source.

'use strict';

const fs = require('fs');
const path = require('path');
const { spawn, spawnSync } = require('child_process');
const { createSessionProxy, createClassifyFrame } = require('./lib/launcher-session-proxy.cjs');

const root = path.resolve(__dirname, '..', '..');
const opencodeDir = path.join(root, '.opencode');
const BLOCKED_CHILD_ENV_RE = /^(NODE_|npm_|NPM_)/;
const DOTENV_ALLOW_RE = /^(SPECKIT_CODE_GRAPH_|SPECKIT_LAUNCHER_IDLE_TIMEOUT_MIN$|MK_CODE_INDEX_)/;

// Load project-local env overrides BEFORE spawning the MCP child. .env.local wins over
// .env, both are gitignored. Existing process.env wins over file values (do not override).
// Minimal parser — no external dependency.
function loadEnvFile(filePath) {
  if (!fs.existsSync(filePath)) return 0;
  let count = 0;
  const raw = fs.readFileSync(filePath, 'utf8');
  for (const line of raw.split('\n')) {
    const trimmed = line.trim();
    if (!trimmed || trimmed.startsWith('#')) continue;
    const m = trimmed.match(/^([A-Za-z_][A-Za-z0-9_]*)\s*=\s*(.*)$/);
    if (!m) continue;
    const key = m[1];
    let val = m[2];
    // Strip matching outer quotes (single or double)
    if ((val.startsWith('"') && val.endsWith('"')) || (val.startsWith("'") && val.endsWith("'"))) {
      val = val.slice(1, -1);
    }
    // The minimal parser is line-oriented; embedded \n in a quoted value would
    // already have terminated the line, but defend explicitly.
    if (val.includes('\n') || val.includes('\0')) {
      process.stderr.write(`[mk-code-index-launcher] env value for ${key} contains control chars; skipping\n`);
      continue;
    }
    if (!DOTENV_ALLOW_RE.test(key)) {
      process.stderr.write(`[mk-code-index-launcher] env ${key} from ${path.basename(filePath)} is not allowlisted; skipping\n`);
      continue;
    }
    if (!(key in process.env)) {
      process.env[key] = val;
      count++;
    }
  }
  return count;
}

function isStrictModeDisabled(value) {
  if (value === undefined || value === null) return false;
  const v = String(value).trim().toLowerCase();
  return v === '0' || v === 'false' || v === 'no' || v === 'off' || v === '';
}

// Category -> INDEX_* env key. Module-level so the launcher and its tests share one source.
const MAINTAINER_CATEGORY_ENV = {
  skills: 'SPECKIT_CODE_GRAPH_INDEX_SKILLS',
  agents: 'SPECKIT_CODE_GRAPH_INDEX_AGENTS',
  commands: 'SPECKIT_CODE_GRAPH_INDEX_COMMANDS',
  specs: 'SPECKIT_CODE_GRAPH_INDEX_SPECS',
  plugins: 'SPECKIT_CODE_GRAPH_INDEX_PLUGINS',
};

// Pure resolver for SPECKIT_CODE_GRAPH_MAINTAINER_MODE: "true" forces every category (back-compat),
// "false"/empty/unset forces none, and a comma list forces the recognized subset (unknown names
// dropped). Returns category names; the caller maps them to env keys via MAINTAINER_CATEGORY_ENV.
function resolveMaintainerModeCategories(rawValue) {
  const raw = (rawValue || '').trim().toLowerCase();
  if (raw === 'true') return Object.keys(MAINTAINER_CATEGORY_ENV);
  if (!raw || raw === 'false') return [];
  return raw.split(',').map((c) => c.trim()).filter((c) => c in MAINTAINER_CATEGORY_ENV);
}

function bootstrapLauncherEnv() {
  for (const fname of ['.env.local', '.env']) {
    const p = path.join(root, fname);
    if (fs.existsSync(p)) {
      const n = loadEnvFile(p);
      if (n > 0) process.stderr.write(`[mk-code-index-launcher] loaded ${n} env(s) from ${fname}\n`);
    }
  }

  // Maintainer-mode override: SPECKIT_CODE_GRAPH_MAINTAINER_MODE selects which .opencode
  // categories to force-index on this machine, overriding whatever the runtime's MCP config
  // injected. Committed configs ship "false" (end-user safe: only code outside .opencode is
  // graphed); a maintainer opts in locally via .env.local (gitignored). Accepts "true" (all
  // five categories, back-compat) or a comma-separated subset such as "skills,plugins" so a
  // maintainer can index just the .opencode folders that hold code without pulling in the rest.
  // Per-call code_graph_scan args (includeSkills, etc.) still override env. See ENV_REFERENCE.md § GRAPH.
  const maintainerCategories = resolveMaintainerModeCategories(process.env.SPECKIT_CODE_GRAPH_MAINTAINER_MODE);
  for (const cat of maintainerCategories) {
    process.env[MAINTAINER_CATEGORY_ENV[cat]] = 'true';
  }
  if (maintainerCategories.length > 0) {
    process.stderr.write(
      `[mk-code-index-launcher] MAINTAINER_MODE: forcing INDEX_* to "true" for ${maintainerCategories.join(', ')}\n`
    );
  }
}

let skillsDir = path.join(opencodeDir, 'skills');
let legacySkillDir = path.join(opencodeDir, 'skill');
let kitDir = path.join(skillsDir, 'system-code-graph');
// DB lives SKILL-LOCAL at mcp_server/database/; SPECKIT_CODE_GRAPH_DB_DIR overrides.
// Former shared location (.opencode/.spec-kit/code-graph/database/) is migrated back on first startup.
let dbDir = path.join(kitDir, 'mcp_server', 'database');
let lockDir = path.join(dbDir, '.mk-code-index-launcher.lockdir');
const PID_FILE_NAME = '.mk-code-index-launcher.json';
const OWNER_LEASE_FILE_NAME = '.code-graph-owner.json';
let stateFile = path.join(dbDir, PID_FILE_NAME);

const rel = (p) => path.relative(root, p) || '.';
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const now = () => new Date().toISOString();
const RESPAWN_REAP_GRACE_MS = 7000;
let childProcess = null;
let ownerLeasePid = null;
let launchStarted = false;

function log(message) {
  process.stderr.write(`[mk-code-index-launcher] ${message}\n`);
}

function loadBridgeModule() {
  try {
    return require('./lib/launcher-ipc-bridge.cjs');
  } catch (error) {
    if (error.code !== 'MODULE_NOT_FOUND') throw error;
    return {
      async maybeBridgeLeaseHolder({ leaseResult }) {
        const startedAt = leaseResult.startedAt ?? new Date(0).toISOString();
        const legacyMarker = leaseResult.legacyPath ? ' (legacy path)' : '';
        const suffix = process.env.SPECKIT_LAUNCHER_BRIDGE_DISABLED === '1' ? '' : ' (no-bridge-socket)';
        process.stdout.write(`LEASE_HELD_BY:${leaseResult.ownerPid} startedAt=${startedAt}${legacyMarker}${suffix}\n`);
        return { action: 'report', reason: 'bridge-module-missing' };
      },
    };
  }
}

// Code-index replayable / unsafe tool sets for the reconnecting session proxy. Read-only structural
// queries are safe to replay across a backend reattach; a full scan or an apply mutates the graph and
// must NOT be replayed (the client re-drives it on a retryable recycle error). The proxy machinery is
// shared with mk-spec-memory; only this tool set differs.
const CODE_INDEX_REPLAYABLE_TOOL_NAMES = new Set([
  'code_graph_query',
  'code_graph_context',
  'code_graph_status',
  'code_graph_classify_query_intent',
  'detect_changes',
]);
const CODE_INDEX_UNSAFE_TOOL_NAMES = new Set([
  'code_graph_scan',
  'code_graph_apply',
  // code_graph_verify is read-mostly but MUTATES when persistBaseline=true (it persists the gold
  // verification baseline), so it must NOT be replayed across a reconnect — the client re-drives it.
  'code_graph_verify',
]);
const classifyCodeIndexFrame = createClassifyFrame({
  replayableToolNames: CODE_INDEX_REPLAYABLE_TOOL_NAMES,
  unsafeToolNames: CODE_INDEX_UNSAFE_TOOL_NAMES,
});

// Bridge a secondary client through the reconnecting session proxy so a code-index owner death no
// longer surfaces as a hard "Connection closed" — the proxy reattaches to the respawned backend and
// replays in-flight read queries. Mirrors the mk-spec-memory wiring; the classifier is the only diff.
function bridgeStdioThroughSessionProxy(socketPath, options = {}) {
  const createProxy = options.createProxy ?? createSessionProxy;
  const sessionProxy = createProxy({
    socketPath,
    stdin: options.stdin ?? process.stdin,
    stdout: options.stdout ?? process.stdout,
    log,
    classify: classifyCodeIndexFrame,
  });
  return sessionProxy.start();
}

function refreshPaths() {
  skillsDir = path.join(opencodeDir, 'skills');
  legacySkillDir = path.join(opencodeDir, 'skill');
  kitDir = path.join(skillsDir, 'system-code-graph');
  dbDir = path.join(kitDir, 'mcp_server', 'database');
  lockDir = path.join(dbDir, '.mk-code-index-launcher.lockdir');
  stateFile = path.join(dbDir, PID_FILE_NAME);
}

function exists(p) {
  return fs.existsSync(p);
}

function canonicalizePath(pathValue) {
  const resolvedPath = path.resolve(pathValue);
  try {
    return fs.realpathSync.native(resolvedPath);
  } catch (error) {
    if (error.code === 'ENOENT') return resolvedPath;
    throw error;
  }
}

function canonicalizeExistingPrefix(pathValue) {
  const resolvedPath = path.resolve(pathValue);
  if (fs.existsSync(resolvedPath)) return fs.realpathSync.native(resolvedPath);

  const segments = [];
  let current = resolvedPath;
  while (!fs.existsSync(current)) {
    const parent = path.dirname(current);
    if (parent === current) return resolvedPath;
    segments.unshift(path.basename(current));
    current = parent;
  }
  return path.join(fs.realpathSync.native(current), ...segments);
}

function isWithinBase(basePath, candidatePath) {
  return candidatePath === basePath || candidatePath.startsWith(`${basePath}${path.sep}`);
}

function isWithinRoot(candidatePath, requireCanonical = false) {
  const canonicalRoot = fs.realpathSync.native(path.resolve(root));
  const normalizedCandidate = canonicalizeExistingPrefix(candidatePath);
  if (!isWithinBase(canonicalRoot, normalizedCandidate)) return false;
  if (!requireCanonical && !fs.existsSync(path.resolve(candidatePath))) return true;
  const candidate = canonicalizePath(candidatePath);
  return isWithinBase(canonicalRoot, candidate);
}

function assertPathWithinRoot(candidatePath, label, requireCanonical = false) {
  if (!isWithinRoot(candidatePath, requireCanonical)) {
    throw new Error(`${label} must stay within workspace root ${root}: ${candidatePath}`);
  }
}

function ensureCanonicalDir(dirPath) {
  assertPathWithinRoot(dirPath, 'code graph DB directory');
  fs.mkdirSync(path.resolve(dirPath), { recursive: true, mode: 0o700 });
  assertPathWithinRoot(dirPath, 'code graph DB directory', true);
  return canonicalizePath(dirPath);
}

function writeState(payload) {
  fs.mkdirSync(dbDir, { recursive: true, mode: 0o700 });
  fs.writeFileSync(stateFile, `${JSON.stringify(payload, null, 2)}\n`);
}

